var e=[{id:`L2_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`......어때?`,JPN:`……どう？`,ENG:`So?`,TWN:`……怎麼樣？`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`바닥을 뒹구는 기분이?`,JPN:`地面に放り出された感想は？`,ENG:`How does it feel to be knocked out cold on the ground?`,TWN:`在地板上打滾的心情如何？`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`......별로 특별할 건 없는데.`,JPN:`……別に、感想と言えるものはないかな。`,ENG:`Nothing special.`,TWN:`……沒什麼特別的。`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`바닥을 기어 다니는 게 이번이 처음도 아니고......`,JPN:`地面を這うのも初めてじゃないし……`,ENG:`It's not like this is my first time doing this, you know.`,TWN:`像這樣趴在地板上也不是第一次了……`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`이것보다 더 심한 꼴도 많이 겪었어.`,JPN:`これよりみじめな経験もたくさんあるよ。`,ENG:`Actually, I've had worse.`,TWN:`比這更糟的經驗多得是。`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`처음 들어간 회사에서는 일주일도 안 돼서 잘리고,`,JPN:`初めて入社した会社は一週間足らずでクビだったし、`,ENG:`I couldn't last for a week in the first company I ever worked for,`,TWN:`第一次上班的公司不到一個星期就被辭退了……`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`첫 다이브 작전에서는 소대장 발목이나 잡고 다녔지......`,JPN:`初ダイブ作戦では、散々小隊長の足を引っ張ってた……`,ENG:`and I was nothing but a burden to my commander on my first dive mission.`,TWN:`第一次躍入作戰的時候拖累了小隊長……`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`......대체 뭘 기대한 거야?`,JPN:`……何を期待してたわけ？`,ENG:`What did you expect?`,TWN:`……妳到底在期待什麼啊？`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`난 C급 카운터라고.`,JPN:`私はC級カウンターなんだよ。`,ENG:`I'm a grade C Counter.`,TWN:`我是C級制裁者。`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`이 회사에 와서 우연히 펜릴 소대에 배치되긴 했지만......`,JPN:`この会社に入って、たまたまフェンリル小隊に配置されたけど……`,ENG:`It just so happened that I started working in my current company and they put me in the Fenrir Squad,`,TWN:`雖然我在這間公司，湊巧地被分配到芬里爾小隊……`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`사실 엘리트라는 이름이 어울리는 건 내가 아니라 너야.`,JPN:`実際のところ、エリートと言われてしっくりくるのは君のほう。`,ENG:`but in reality, the title "elite" suits you much better than it does me.`,TWN:`但實際上能稱得上精英的不是我，是妳。`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`그렇지 않아?`,JPN:`そう思わない？`,ENG:`Don't you see it?`,TWN:`不是嗎？`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`왜 내게 그렇게 경쟁의식을 불태우는 건지...... 난 이해를 못하겠어.`,JPN:`どうしてそこまで私にライバル意識を持っているのか……
私にはよくわからないよ。`,ENG:`Why are you so desperately trying to compete with me? I just can't wrap my head around it.`,TWN:`為什麼會對我有那麼強的競爭意識……我實在是無法理解。`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`......그것 참 힘 빠지는 소리를 잘도 하네.`,JPN:`……これは、自覚がなさ過ぎてまいっちゃうね。`,ENG:`That's... a disappointing reaction.`,TWN:`……妳還真是會說喪氣話呢。`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`네 말이 다 맞다고 치더라도......`,JPN:`あなたの話が本当にそのとおりだとしても……`,ENG:`Let's say you're right about all that.`,TWN:`就算妳說得都對……`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`그럼 네가 들고 다니는 저 검은 뭐지?`,JPN:`それじゃあ、あなたが持ち歩くあの剣は何？`,ENG:`Then what's that sword you're carrying with you?`,TWN:`那妳拿著的那把劍又是什麼？`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`네가 처치한 그림자는, 리플레이서 간부들은 또 어떻고?`,JPN:`あなたが倒したシャドウやリプレイサー幹部はどう説明するの？`,ENG:`And what about all the Shadows and Replacer officers you've defeated?`,TWN:`妳打倒了暗影，妳解決了克隆集團的幹部又是怎麼說？`},stage:{bg:`MAINSTREAM_5302011`,slots:{L:null,C:null,R:null}}}];export{e as default};